const raw = $input.item.json;
const normalized = {
  student_id: raw.student_id || 'unknown_std',
  analysis_mode: raw.analysis_mode || 'prioritize',
  timezone: raw.timezone || 'UTC',
  preferred_tone: raw.preferred_tone || 'concise',
  student_profile: {
    name: raw.student_profile?.name || 'Academic User',
    academic_level: raw.student_profile?.academic_level || 'university_undergrad',
    courses: raw.student_profile?.courses || [],
    weekly_available_study_hours: Number(raw.student_profile?.weekly_available_study_hours || 15.0)
  },
  deadline_items: (raw.deadline_items || []).map(item => ({
    title: item.title || 'Untitled Task',
    course_name: item.course_name || 'Unassigned Course',
    deadline_type: item.deadline_type || 'assignment',
    due_date: item.due_date || null,
    estimated_hours: item.estimated_hours ? Number(item.estimated_hours) : null,
    weight_percent: item.weight_percent ? Number(item.weight_percent) : 0.0,
    importance_level: item.importance_level || 'medium',
    source: item.source || 'manual',
    status: item.status || 'not_started',
    notes: item.notes || ''
  })),
  calendar_constraints: {
    busy_slots: raw.calendar_constraints?.busy_slots || [],
    quiet_hours: raw.calendar_constraints?.quiet_hours || []
  },
  study_preferences: {
    block_length_minutes: Number(raw.study_preferences?.block_length_minutes || 90),
    preferred_reminder_channel: raw.study_preferences?.preferred_reminder_channel || 'email',
    preferred_study_times: raw.study_preferences?.preferred_study_times || ['afternoon']
  }
};

return {
  json: {
    ...normalized,
    _debug_normalized_input: true
  }
};

const data = $input.item.json;
const validation = {
  valid: true,
  errors: [],
  missing_fields: []
};

if (!data.student_id || data.student_id === 'unknown_std') {
  validation.missing_fields.push('student_id');
}

if (!data.deadline_items || data.deadline_items.length === 0) {
  validation.valid = false;
  validation.errors.push('No deadline items provided in inventory.');
}

data.deadline_items.forEach((item, index) => {
  if (!item.due_date) {
    validation.errors.push(`Item at index ${index} (${item.title}) is missing a due date.`);
  }
});

return {
  json: {
    ...data,
    _debug_validation: validation
  }
};

const data = $input.item.json;
const now = new Date();
const checked_items = [];
const overdue_items = [];
const warnings = [];

data.deadline_items.forEach(item => {
  if (!item.due_date) {
    warnings.push(`Missing due date for: ${item.title}`);
    return;
  }

  const due = new Date(item.due_date);
  if (isNaN(due.getTime())) {
    warnings.push(`Invalid date format for: ${item.title}`);
    return;
  }

  const is_overdue = due < now && item.status !== 'completed';
  if (is_overdue) {
    overdue_items.push({
      title: item.title,
      course: item.course_name,
      days_overdue: Math.round((now - due) / (1000 * 60 * 60 * 24))
    });
  }

  checked_items.push({
    ...item,
    _debug_is_overdue: is_overdue
  });
});

return {
  json: {
    ...data,
    deadline_items: checked_items,
    _debug_overdue: overdue_items,
    _debug_warnings: warnings
  }
};

const data = $input.item.json;
const now = new Date();

const scored_items = data.deadline_items.map(item => {
  let score = 0;

  // 1. Time urgency calculation
  if (item.due_date) {
    const due = new Date(item.due_date);
    const diff_time = due - now;
    const diff_days = diff_time / (1000 * 60 * 60 * 24);

    if (diff_days <= 1) score += 50;      // Highly Urgent
    else if (diff_days <= 3) score += 40;
    else if (diff_days <= 7) score += 25;
    else if (diff_days <= 14) score += 10;
  }

  // 2. Grade weight calculation
  if (item.weight_percent >= 20.0) score += 30;
  else if (item.weight_percent >= 10.0) score += 20;
  else if (item.weight_percent > 0) score += 10;

  // 3. Effort score
  const hours = item.estimated_hours || 2.0;
  if (hours >= 10.0) score += 20;
  else if (hours >= 4.0) score += 14;
  else score += 6;

  // 4. Overdue boost
  if (item._debug_is_overdue) score += 25;

  score = Math.min(score, 100);

  let tier = 'routine';
  if (score >= 80) tier = 'critical';
  else if (score >= 50) tier = 'important';

  return {
    ...item,
    priority_score: score,
    priority_tier: tier
  };
});

return {
  json: {
    ...data,
    deadline_items: scored_items,
    _debug_scoring_completed: true
  }
};

string.value:
=Create an academic prioritization report based on the following student data:

Student Profile:
Level: {{$json.student_profile.academic_level}}
Availability: {{$json.student_profile.weekly_available_study_hours}} hrs/week
Timezone: {{$json.timezone}}

Deadline Items:
{{JSON.stringify($json.deadline_items)}}

Calendar constraints:
{{JSON.stringify($json.calendar_constraints.busy_slots)}}

Remember: Do not add motivational text. Return strictly valid JSON.

parameters.jsCode:
const response = $input.item.json.response || '';
let cleanJson = response.trim();

// Strip markdown JSON wrapping if present
if (cleanJson.startsWith('```json')) {
  cleanJson = cleanJson.substring(7);
}
if (cleanJson.endsWith('```')) {
  cleanJson = cleanJson.substring(0, cleanJson.length - 3);
}
cleanJson = cleanJson.trim();

try {
  const parsed = JSON.parse(cleanJson);
  return {
    json: {
      ...parsed,
      status: 'success',
      _debug_llm_parse_success: true
    }
  };
} catch (e) {
  return {
    json: {
      status: 'fallback',
      analysis_summary: 'Failed to parse AI prioritization response.',
      needs_human_review: true,
      review_reason: 'Malformed JSON from AI model node: ' + e.message
    }
  };
}

const parsed = $input.item.json;
const original = $node["Calculate Priority Signals"].json;

// Deterministic Quality Check: Compare original deadline list size to parsed priorities size
if (parsed.status === 'success' && parsed.top_priorities) {
  const parsedTitles = parsed.top_priorities.map(t => t.title);
  const originalTitles = original.deadline_items.map(t => t.title);

  // Check if LLM missed items or fabricated items
  const missing = originalTitles.filter(t => !parsedTitles.includes(t));
  if (missing.length > 0) {
    parsed.needs_human_review = true;
    parsed.review_reason = (parsed.review_reason || '') + ` AI prioritization missed original items: ${missing.join(', ')}.`;
  }
}

return { json: parsed };

